parameters.jsCode:
const items = $input.all();

return items.map(item => {
  const execution = item.json.execution ?? {};
  const workflow = item.json.workflow ?? {};
  const error = execution.error ?? {};

  const timestamp = error.timestamp;

  let readableTimestamp = "N/A";
  let errorTimestamp = null;

  if (timestamp) {
    const date = new Date(timestamp);

    errorTimestamp = date.toISOString();

    const formatter = new Intl.DateTimeFormat("en-US", {
      timeZone: "Asia/Manila",
      month: "long",
      day: "2-digit",
      year: "numeric",
      hour: "2-digit",
      minute: "2-digit",
      second: "2-digit",
      hour12: false
    });

    readableTimestamp = formatter.format(date);
  }

  return {
    json: {
      // n8n execution details
      execution_id: String(execution.id ?? ""),
      execution_url: execution.url ?? null,

      // workflow details
      workflow_id: workflow.id ?? null,
      workflow_name: workflow.name ?? null,

      // execution metadata
      mode: execution.mode ?? null,
      last_node_executed: execution.lastNodeExecuted ?? null,

      // error details
      error_name: error.name ?? null,
      error_message: error.message ?? null,
      error_timestamp: errorTimestamp,

      // for ClickUp/Slack only
      readableTimestamp,

      // bug tracking
      status: "reported",
      severity: error.name === "WorkflowCrashedError" ? "high" : "medium",
      source: "n8n_error_trigger",

      // raw/debug fields
      error_context: error.context ?? {},
      raw_payload: item.json
    }
  };
});
